1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  amulet: 60,
13	  staff: 80,
14	};
15	
16	const FIRST_INSURANCE_RATE = 0.1;
17	const PROCESSING_FEE = 5;
18	
19	const quotePremium = (step: QuoteStep): number => {
20	  const policyBase = step.items.reduce(
21	    (sum, item) => sum + BASE_PREMIUM[item.type],
22	    0,
23	  );
24	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
25	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
26	};
27	
28	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
29	  return {
30	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
31	  };
32	};
