1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge / simplest cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single main item base premiums (+ fee, no other modifiers; newcomer 0y first insurance) ---
15	  // Note: simplest isolated base premium tests use a long-standing customer's follow-up to neutralise,
16	  // but we start with raw single-item quotes where only fee + first-insurance apply per spec.
17	
18	  // --- Base premium per item type (isolated, expressed via newcomer single quote) ---
19	  it("single amulet (newcomer) → premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
20	    const result = runScenario({
21	      customer: { yearsWithMHPCO: 0 },
22	      steps: [
23	        {
24	          op: "quote",
25	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
26	        },
27	      ],
28	    });
29	    expect(result).toEqual({ results: [{ premium: 71 }] });
30	  });
31	  it("single staff (newcomer) → premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
32	    const result = runScenario({
33	      customer: { yearsWithMHPCO: 0 },
34	      steps: [
35	        {
36	          op: "quote",
37	          items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }],
38	        },
39	      ],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 93 }] });
42	  });
43	  it.todo("single potion base premium 40 G");
44	  it.todo("single sword base premium 100 G");
45	
46	  // --- Components and building blocks (base premium only) ---
47	  it.todo("2 runes → 50 G base premium");
48	  it.todo("3 runes → 60 G base premium (block applies)");
49	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
50	  it.todo("7 runes → 175 G base premium");
51	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
52	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
53	
54	  // --- Premium modifiers (item-specific) ---
55	  it.todo("cursed sword (steel, ench 3), newcomer → premium 165 G");
56	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
57	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
58	
59	  // --- Modifier scope on multi-item policies ---
60	  it.todo("cursed sword + plain amulet → curse adds 50 G (50% of sword base, not policy total) → 210 G before fee");
61	
62	  // --- Policy-wide modifiers ---
63	  it.todo("customer with exactly 2 years → loyalty discount applies");
64	
65	  // --- Rounding ---
66	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
67	
68	  // --- Integration examples (premium) ---
69	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
70	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3y → premium 160 G");
71	
72	  // --- Claims: standard reimbursement ---
73	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
74	  it.todo("rune damage 200 → payout 100 (full minus deductible; no special clause)");
75	
